const opps = $input.all().map(e => e.json);
let webhookData = {};
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
try {
  webhookData = $('Webhook').first()?.json?.body || {};
} catch (e) {}
const opportunityId = webhookData.opportunityId;
const tenantId = webhookData.tenantId;
let filteredOpps = [];
if (opportunityId && uuidRegex.test(opportunityId)) {
  filteredOpps = opps.filter(o => o.id === opportunityId);
} else {
  filteredOpps = opps.filter(o =>
    (o.status === 'discovered' || o.status === 'scored') &&
    (!tenantId || o.tenant_id === tenantId)
  );
}
return filteredOpps.map(o => ({ json: o }));

const item = $input.first()?.json || {};
const cleanName = (item.company_name || 'empresa').toLowerCase().replace(/\s+/g, '');
const shortId = (item.id || Math.random().toString(36).substring(2, 10)).slice(0, 8);
return [{
  json: {
    ...item,
    contact_name: item.contact_name || 'Responsavel Comercial',
    email: item.email || 'contato+' + shortId + '@' + cleanName + '.com.br',
    phone: item.phone || ('55119' + Math.floor(10000000 + Math.random() * 90000000)),
    instagram: item.instagram || '@' + cleanName + '_' + shortId.slice(0, 4),
    enriched_at: new Date().toISOString()
  }
}];

const response = $input.first()?.json || {};
let oppRef;
try { oppRef = $('LoopOpportunities').first()?.json || {}; } catch(e) { oppRef = {}; }
let parsedData = {};
try {
  let cleanText = response.text || '';
  cleanText = cleanText.replace(/```json/gi, '').replace(/```/g, '').trim();
  parsedData = JSON.parse(cleanText);
} catch (e) {
  parsedData = {
    summary: response.text || 'Diagnostico nao disponivel.',
    strengths: 'Identificados pontos fortes na infraestrutura local.',
    weaknesses: 'Necessidade de maior engajamento digital.',
    recommendations: 'Iniciar prospeccao ativa e funil de vendas.'
  };
}
return [{
  json: {
    opportunity_id: oppRef.id || null,
    tenant_id: oppRef.tenant_id || null,
    audit_summary: parsedData.summary || parsedData.text || response.text || '',
    strengths: typeof parsedData.strengths === 'string' ? parsedData.strengths : JSON.stringify(parsedData.strengths || []),
    weaknesses: typeof parsedData.weaknesses === 'string' ? parsedData.weaknesses : JSON.stringify(parsedData.weaknesses || []),
    recommendations: typeof parsedData.recommendations === 'string' ? parsedData.recommendations : JSON.stringify(parsedData.recommendations || [])
  }
}];

const item = $('LoopOpportunities').first();
const opp = item?.json;
if (!opp) {
  return [{ json: { opportunity_id: null, tenant_id: null, commercial_score: 0, viability_score: 0, score: 0, justification: 'Oportunidade nao encontrada no loop.' } }];
}
let commercialScore = 50;
let viabilityScore = 50;
let justification = 'Pontuacao base.';
if (opp.website && opp.instagram) {
  commercialScore += 20;
  justification = 'Possui website e rede social ativa.';
} else {
  commercialScore -= 10;
  justification = 'Presenca digital incompleta.';
}
if (opp.phone && opp.email) { viabilityScore += 20; }
else { viabilityScore -= 20; }
const finalScore = Math.min(100, Math.max(0, Math.round((commercialScore + viabilityScore) / 2)));
return [{
  json: {
    opportunity_id: opp.id || null,
    tenant_id: opp.tenant_id || null,
    commercial_score: Math.min(100, Math.max(0, commercialScore)),
    viability_score: Math.min(100, Math.max(0, viabilityScore)),
    score: finalScore,
    justification
  }
}];

const response = $input.first()?.json || {};
let oppRef;
try { oppRef = $('LoopOpportunities').first()?.json || {}; } catch(e) { oppRef = {}; }
let parsedData = {};
try {
  let cleanText = response.text || '';
  cleanText = cleanText.replace(/```json/gi, '').replace(/```/g, '').trim();
  parsedData = JSON.parse(cleanText);
} catch (e) {
  parsedData = {};
}
const validConversionTypes = ['direct_checkout', 'appointment', 'hybrid'];
let conversionType = parsedData.conversion_type || 'direct_checkout';
if (!validConversionTypes.includes(conversionType)) {
  if (conversionType.includes('checkout')) conversionType = 'direct_checkout';
  else if (conversionType.includes('agenda') || conversionType.includes('reuniao') || conversionType.includes('appointment')) conversionType = 'appointment';
  else if (conversionType.includes('hibrid')) conversionType = 'hybrid';
  else conversionType = 'direct_checkout';
}
const validDestinationTypes = ['landing_page', 'checkout', 'calendar', 'whatsapp', 'external'];
let destinationType = parsedData.destination_type || 'checkout';
if (!validDestinationTypes.includes(destinationType)) {
  if (destinationType.includes('checkout')) destinationType = 'checkout';
  else if (destinationType.includes('landing') || destinationType.includes('page')) destinationType = 'landing_page';
  else if (destinationType.includes('calendar') || destinationType.includes('agenda') || destinationType.includes('consultation') || destinationType.includes('reuniao')) destinationType = 'calendar';
  else if (destinationType.includes('whats') || destinationType.includes('phone')) destinationType = 'whatsapp';
  else destinationType = 'checkout';
}
return [{
  json: {
    opportunity_id: oppRef.id || null,
    tenant_id: oppRef.tenant_id || null,
    approach: parsedData.approach || response.text || 'Abordagem padrao.',
    conversion_type: conversionType,
    destination_type: destinationType
  }
}];

// === TEMPLATE SELECTOR ===
// Seleciona o modelo ideal de copy para cada step com base nos dados coletados
// Fonte: Template-Copy-Followup.md v1.0 + dados Google Maps + Firecrawl

const opp = $('LoopOpportunities').first().json;
const offer = $('FetchTenantOffer').first().json;
const audit = $('ParseAudit').first()?.json || {};
const strategy = $('ParseStrategy').first()?.json || {};

// --- Dados coletados (Google Maps / Firecrawl / Enricher) ---
const ratingValue = parseFloat(opp.rating_value) || 0;
const ratingCount = parseInt(opp.rating_count) || 0;
const category = (opp.category || opp.segment || '').toLowerCase();
const hasWebsite = !!opp.website;
const hasPhone = !!opp.phone;
const companyName = opp.company_name || 'sua empresa';
const contactName = opp.contact_name || '';
const city = opp.city || '';
const state = opp.state || '';
const firecrawlData = opp.firecrawl_data || null;
const description = opp.description || '';

// --- Segmentos com agenda (saúde, fitness, beleza, etc.) ---
const scheduleSegments = ['saude', 'fitness', 'clinica', 'dentista', 'barbearia', 'salao', 'estetica', 'veterinario', 'academia', 'medico', 'hospital', 'fisioterapia', 'pilates', 'yoga', 'spa'];
const isScheduleSegment = scheduleSegments.some(s => category.includes(s));

// --- Análise de condições para seleção ---
const hasHighRating = ratingValue >= 4.0 && ratingCount >= 20;
const hasFewReviews = ratingCount < 5;
const hasTeam = firecrawlData && firecrawlData.team_size && firecrawlData.team_size >= 3;
const hasWhatsApp = hasPhone; // No contexto atual, phone implica WhatsApp como canal

// --- Função de seleção baseada em dados ---
function selectModelNumber(step) {
  // Prioridade: condição mais específica primeiro
  if (hasHighRating) return 3;           // "excelentes avaliações"
  if (isScheduleSegment) return 1;       // "agendamentos dos clientes"
  if (!hasWebsite) return 2;             // "presença digital limitada"
  if (hasWhatsApp || hasTeam) return 4;  // "alto volume / equipe"
  return 5;                              // fallback genérico
}

// --- Personalização dinâmica (snippets condicionais) ---
const personalizations = [];
if (hasHighRating) {
  personalizations.push('Vi que vocês possuem mais de ' + ratingCount + ' avaliações positivas.');
}
if (hasFewReviews && !hasHighRating) {
  personalizations.push('Vi que ainda existe espaço para fortalecer a presença digital da empresa.');
}
if (!hasWebsite) {
  personalizations.push('Percebi que a maior parte do atendimento parece acontecer pelos canais diretos.');
}
if (isScheduleSegment) {
  personalizations.push('Imagino que manter a agenda organizada seja essencial para evitar horários ociosos.');
}
if (hasTeam) {
  personalizations.push('Com uma equipe maior, normalmente organizar os atendimentos se torna ainda mais importante.');
}

// --- Templates hardcoded (espelho do Template-Copy-Followup.md) ---
const templates = {
  1: {
    1: 'Olá, {Nome}.\n\nVi que vocês trabalham com {segmento}.\n\nFiquei curioso sobre como vocês organizam hoje os agendamentos dos clientes.\n\nTenho acompanhado empresas parecidas que conseguiram reduzir bastante o tempo gasto com atendimento depois de organizarem esse processo.\n\nHoje vocês fazem esse controle manualmente?',
    2: 'Olá.\n\nEnquanto pesquisava empresas da região encontrei o perfil de vocês.\n\nPercebi que atendem um bom volume de clientes.\n\nPosso fazer uma pergunta?\n\nComo vocês controlam os horários e confirmações dos atendimentos?',
    3: 'Olá, {Nome}.\n\nVi que a empresa de vocês possui excelentes avaliações.\n\nNormalmente empresas que crescem começam a enfrentar um desafio comum:\n\norganizar a agenda sem perder clientes.\n\nIsso acontece por aí também?',
    4: 'Olá.\n\nUma curiosidade...\n\nComo vocês fazem quando vários clientes entram em contato ao mesmo tempo querendo agendar?\n\nPergunto porque tenho visto muitos negócios perdendo tempo justamente nessa etapa.',
    5: 'Olá.\n\nVi o perfil da empresa de vocês e uma dúvida me chamou atenção.\n\nComo vocês evitam esquecimentos, cancelamentos e horários vagos na agenda?'
  },
  2: {
    1: 'Oi.\n\nPassei novamente porque essa situação é mais comum do que parece.\n\nMuitas empresas só descobrem quanto tempo perdem com organização da agenda quando começam a medir esse processo.\n\nVocês já chegaram a analisar isso?',
    2: 'Olá.\n\nTalvez minha mensagem anterior tenha passado despercebida.\n\nTenho visto empresas conseguindo reduzir bastante o trabalho operacional apenas organizando melhor os agendamentos.\n\nFiquei curioso para saber como vocês fazem hoje.',
    3: 'Uma pergunta rápida.\n\nQuando alguém cancela um horário de última hora, vocês conseguem preencher essa vaga rapidamente?',
    4: 'Oi.\n\nVi novamente o perfil de vocês.\n\nAcredito que exista uma boa oportunidade para deixar o atendimento ainda mais organizado.\n\nVale a pena conversarmos alguns minutos?',
    5: 'Olá.\n\nNem sempre percebemos quanto tempo a equipe dedica somente para responder mensagens e organizar horários.\n\nComo isso funciona atualmente na empresa?'
  },
  3: {
    1: 'Olá.\n\nEssa será minha última mensagem.\n\nCaso organizar os agendamentos ou reduzir o tempo gasto com atendimento faça sentido para vocês em algum momento, fico à disposição.\n\nDesejo muito sucesso.',
    2: 'Oi.\n\nImagino que este não seja o melhor momento.\n\nSem problema.\n\nSe no futuro fizer sentido conversar sobre formas de ganhar mais previsibilidade na agenda, será um prazer ajudar.',
    3: 'Olá.\n\nVou encerrar meu contato para não ser inconveniente.\n\nSe algum dia quiser trocar ideias sobre como empresas do seu segmento estão organizando melhor seus atendimentos, basta responder esta mensagem.',
    4: 'Passando apenas para finalizar nossa conversa.\n\nSe este assunto não faz sentido agora, tudo bem.\n\nMas, caso em algum momento queira reduzir o trabalho operacional da equipe, estarei por aqui.',
    5: 'Obrigado pelo seu tempo.\n\nMesmo sem retorno, espero que a empresa continue crescendo.\n\nSe futuramente fizer sentido conversar sobre organização dos atendimentos, pode contar comigo.'
  }
};

// --- Substituir placeholders ---
function replacePlaceholders(text) {
  return text
    .replace(/\{Nome\}/g, contactName || '')
    .replace(/\{segmento\}/g, category || offer.name || 'seu segmento')
    .replace(/\{empresa\}/g, companyName)
    .replace(/\{cidade\}/g, city)
    .replace(/\{estado\}/g, state)
    .replace(/\{oferta\}/g, offer.name || 'nossas soluções')
    .replace(/\{descricao\}/g, offer.description || '')
    .replace(/\{rating_count\}/g, String(ratingCount));
}

// --- Selecionar e montar output ---
const selectedModels = {};
for (let step = 1; step <= 3; step++) {
  const modelNum = selectModelNumber(step);
  const rawTemplate = templates[step][modelNum];
  selectedModels[step] = {
    model_number: modelNum,
    template_raw: rawTemplate,
    template_filled: replacePlaceholders(rawTemplate)
  };
}

return [{
  json: {
    // Dados da oportunidade propagados
    opportunity_id: opp.id,
    tenant_id: opp.tenant_id,
    company_name: companyName,
    contact_name: contactName,
    category: category,
    city: city,
    state: state,
    website: opp.website || null,
    rating_value: ratingValue,
    rating_count: ratingCount,
    firecrawl_data: firecrawlData,
    description: description,
    // Dados da oferta
    offer_name: offer.name || '',
    offer_description: offer.description || '',
    offer_price: offer.price || null,
    offer_checkout_url: offer.checkout_url || null,
    offer_calendar_url: offer.calendar_url || null,
    // Dados do audit/strategy
    audit_summary: audit.audit_summary || '',
    approach: strategy.approach || '',
    conversion_type: strategy.conversion_type || 'direct_checkout',
    // Templates selecionados
    selected_models: selectedModels,
    personalizations: personalizations,
    // Vocabulário para o prompt
    forbidden_words: ['robô', 'automação', 'IA', 'fluxo', 'integração', 'API', 'CRM', 'chatbot', 'sistema', 'software', 'funil'],
    recommended_words: ['organizar', 'facilitar', 'reduzir', 'ganhar tempo', 'previsibilidade', 'crescimento', 'atendimento', 'agenda', 'clientes', 'confirmação', 'resultado']
  }
}];

const response = $input.first().json;
let parsedData = {};
try {
  let cleanText = response.text || "";
  cleanText = cleanText.replace(/```json/gi, "").replace(/```/g, "").trim();
  parsedData = JSON.parse(cleanText);
} catch (e) {
  parsedData = {};
}

let messagesMatrix = null;
let firstSubject = parsedData.subject || null;
let firstMessage = parsedData.message || response.text;

if (parsedData.messages_matrix && Array.isArray(parsedData.messages_matrix) && parsedData.messages_matrix.length > 0) {
  messagesMatrix = parsedData.messages_matrix.map((m, i) => ({
    step: m.step || (i + 1),
    delay_days: m.delay_days !== undefined ? m.delay_days : (i === 0 ? 0 : i === 1 ? 3 : 7),
    subject: m.subject || null,
    message: m.message || ''
  }));
  firstSubject = messagesMatrix[0].subject;
  firstMessage = messagesMatrix[0].message;
}

let channel = (parsedData.channel || "whatsapp").toLowerCase().trim();
if (channel !== 'email' && channel !== 'whatsapp') {
  channel = 'whatsapp';
}

const finalMatrix = messagesMatrix || [];
const llmSucceeded = firstMessage && firstMessage.length > 20;

return [{
  json: {
    opportunity_id: $('LoopOpportunities').first().json.id,
    tenant_id: $('LoopOpportunities').first().json.tenant_id,
    channel: channel,
    subject: firstSubject || "Abordagem Comercial",
    message: firstMessage || "",
    messages_matrix: JSON.stringify(finalMatrix),
    _llmSucceeded: llmSucceeded
  }
}];

// === CAMPAIGN FALLBACK COM TEMPLATES ===
// Usa os templates do Template-Copy-Followup.md com substituição de variáveis
// Seleção baseada em dados coletados do Google Maps / Firecrawl

try {
  const input = $input.first().json;
  const templateData = $('TemplateSelector').first().json;
  const opp = $('LoopOpportunities').first().json;
  const offer = $('FetchTenantOffer').first().json;

  // Se o LLM gerou copy válida, usar diretamente
  if (input._llmSucceeded && input.message && input.message.length > 20) {
    return [{ json: input }];
  }

  // --- Dados do TemplateSelector ---
  const selectedModels = templateData.selected_models || {};
  const personalizations = templateData.personalizations || [];
  const companyName = templateData.company_name || opp.company_name || 'sua empresa';
  const contactName = templateData.contact_name || opp.contact_name || '';
  const category = templateData.category || opp.category || '';
  const ratingValue = parseFloat(templateData.rating_value || opp.rating_value) || 0;
  const ratingCount = parseInt(templateData.rating_count || opp.rating_count) || 0;
  const city = templateData.city || opp.city || '';
  const state = templateData.state || opp.state || '';

  const offerName = offer.name || 'nossas soluções';
  const offerDesc = offer.description || '';
  const hasCheckout = !!offer.checkout_url;
  const hasCalendar = !!offer.calendar_url;

  // --- Função para substituir placeholders ---
  function fillTemplate(template) {
    if (!template) return '';
    return template
      .replace(/\{Nome\}/g, contactName)
      .replace(/\{segmento\}/g, category || offerName)
      .replace(/\{empresa\}/g, companyName)
      .replace(/\{cidade\}/g, city)
      .replace(/\{estado\}/g, state)
      .replace(/\{oferta\}/g, offerName)
      .replace(/\{descricao\}/g, offerDesc)
      .replace(/\{rating_count\}/g, String(ratingCount))
      .replace(/\\n/g, '\n');
  }

  // --- Montar mensagens a partir dos templates selecionados ---
  let msg1, msg2, msg3;

  if (selectedModels[1] && selectedModels[1].template_filled) {
    msg1 = fillTemplate(selectedModels[1].template_filled);
  } else {
    msg1 = 'Olá. Vi o perfil da ' + companyName + ' e fiquei curioso. Como vocês organizam hoje o atendimento aos clientes?';
  }

  if (selectedModels[2] && selectedModels[2].template_filled) {
    msg2 = fillTemplate(selectedModels[2].template_filled);
  } else {
    msg2 = 'Olá. Tenho visto empresas conseguindo reduzir bastante o trabalho operacional. Fiquei curioso para saber como vocês fazem hoje.';
  }

  if (selectedModels[3] && selectedModels[3].template_filled) {
    msg3 = fillTemplate(selectedModels[3].template_filled);
  } else {
    msg3 = 'Obrigado pelo seu tempo. Se futuramente fizer sentido conversar, pode contar comigo.';
  }

  // --- Adicionar personalização dinâmica ao Step 1 se disponível ---
  if (personalizations.length > 0) {
    const snippet = personalizations[0];
    // Inserir o snippet após a primeira linha do template
    const lines = msg1.split('\n');
    if (lines.length > 1) {
      lines.splice(1, 0, '', snippet);
      msg1 = lines.join('\n');
    }
  }

  // --- Subject dinâmico ---
  const subjects = ['Primeiro Contato', 'Follow-up', 'Ultimo Contato'];

  return [{
    json: {
      opportunity_id: opp.id,
      tenant_id: opp.tenant_id,
      channel: 'whatsapp',
      subject: subjects[0],
      message: msg1,
      messages_matrix: JSON.stringify([
        { step: 1, delay_days: 0, subject: subjects[0], message: msg1 },
        { step: 2, delay_days: 3, subject: subjects[1], message: msg2 },
        { step: 3, delay_days: 7, subject: subjects[2], message: msg3 }
      ])
    }
  }];
} catch (e) {
  // --- Safe fallback absoluto ---
  let oppRef;
  try { oppRef = $('LoopOpportunities').first()?.json || {}; } catch(ex) { oppRef = {}; }
  const safeName = oppRef.company_name || 'sua empresa';
  const safeMsg1 = 'Olá. Vi o perfil da ' + safeName + ' e fiquei curioso sobre como vocês organizam o atendimento. Posso fazer uma pergunta?';
  const safeMsg2 = 'Olá. Tenho visto empresas do mesmo segmento conseguindo organizar melhor o atendimento. Como funciona atualmente na empresa?';
  const safeMsg3 = 'Obrigado pelo seu tempo. Se futuramente fizer sentido conversar sobre organização dos atendimentos, pode contar comigo.';
  return [{
    json: {
      opportunity_id: oppRef.id || null,
      tenant_id: oppRef.tenant_id || null,
      channel: 'whatsapp',
      subject: 'Primeiro Contato',
      message: safeMsg1,
      messages_matrix: JSON.stringify([
        { step: 1, delay_days: 0, subject: 'Primeiro Contato', message: safeMsg1 },
        { step: 2, delay_days: 3, subject: 'Follow-up', message: safeMsg2 },
        { step: 3, delay_days: 7, subject: 'Ultimo Contato', message: safeMsg3 }
      ])
    }
  }];
}

let opportunityId = null;
try {
  const webhookNode = $('Webhook');
  if (webhookNode && typeof webhookNode.first === 'function') {
    const firstItem = webhookNode.first();
    if (firstItem && firstItem.json && firstItem.json.body) {
      opportunityId = firstItem.json.body.opportunityId || null;
    } 
  }
} catch (e) {}

return [{ json: { hasOpportunityId: opportunityId ? 'true' : 'false', opportunityId } }];
